class Store:
    def __init__(self):
        self._data = {}
        self._version = 0

    def set(self, key, value):
        self._data[key] = value
        self._version += 1
        return self._version

    def get(self, key, default=None):
        if key in self._data:
            return self._data[key]
        return default
